def create_project(dest_dir='.'):
    print("Extracting project files...")
    for relpath, b64content in files.items():
        # Ensure correct path separators for the target OS
        filepath = os.path.join(dest_dir, os.path.normpath(relpath))
        os.makedirs(os.path.dirname(filepath), exist_ok=True)
        with open(filepath, 'wb') as f:
            f.write(base64.b64decode(b64content))
        print(f"Created {filepath}")
    print("Project successfully created!")

if __name__ == '__main__':
    create_project()
